import React from "react";

export function Sparkline({ data, width = 80, height = 28 }) {
  if (!data || data.length < 2) return null;

  const values = data.map((d) => d.weight);
  const min = Math.min(...values);
  const max = Math.max(...values);
  const range = max - min || 1;

  const pts = values.map((v, i) => {
    const x = (i / (values.length - 1)) * width;
    const y = height - ((v - min) / range) * (height - 4) - 2;
    return `${x},${y}`;
  });

  const last = pts[pts.length - 1].split(",");

  return (
    <svg width={width} height={height} style={{ overflow: "visible" }}>
      <defs>
        <linearGradient id="spark-grad" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor="#C8F542" stopOpacity="0.35" />
          <stop offset="100%" stopColor="#C8F542" stopOpacity="0" />
        </linearGradient>
      </defs>
      {/* Fill area */}
      <path
        d={`M${pts[0]} ${pts.slice(1).map((p) => `L${p}`).join(" ")} L${width},${height} L0,${height} Z`}
        fill="url(#spark-grad)"
      />
      {/* Line */}
      <polyline
        points={pts.join(" ")}
        fill="none"
        stroke="#C8F542"
        strokeWidth="1.5"
        strokeLinejoin="round"
        strokeLinecap="round"
      />
      {/* Last dot */}
      <circle cx={last[0]} cy={last[1]} r="3" fill="#C8F542" />
    </svg>
  );
}
